#include <vector>

template<typename T>
void swapElements(std::vector<T>& vec, size_t pos1, size_t pos2) {
    if(pos1 > vec.size() || pos2 > vec.size() || pos1 == pos2) {
        // Error handling or exception can be placed here
        std::cerr << "Invalid positions or same position provided.\n";
        return;
    }

    T temp1 = vec[pos1];
    T temp2 = vec[pos2];

    vec.erase(vec.begin() + pos2);
    vec.insert(vec.begin() + pos2, temp1);

    vec.erase(vec.begin() + pos1);
    vec.insert(vec.begin() + pos1, temp2);
}

